            args = CopyObjectArgs.builder()
                    .bucket(path)
                    .object(metaData.getFileName())
                    .source(CopySource.builder().bucket(path).object(metaData.getFileName() + uuid).build())
                    .headers(toMinioMetaData(metaData.getMetaData()))  // 添加新的元数据
